# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify, abort
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(80), unique=True, nullable=False)
    role = db.Column(db.String(20), nullable=False)  # Expected: user, moderator, admin
    account_status = db.Column(db.String(20), nullable=False)  # Expected: active, suspended
    subscription_tier = db.Column(db.String(20), nullable=False)  # Expected: free, pro, enterprise

# Simulated current_user; in a real application this would be provided by your auth system
class CurrentUser:
    def __init__(self, role):
        self.role = role

def get_current_user():
    # For demonstration purposes, we're returning an admin user.
    return CurrentUser(role="admin")

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    current_user = get_current_user()
    if current_user.role != "admin":
        abort(403, description="Forbidden: Admin access required.")

    user = User.query.get(user_id)
    if not user:
        abort(404, description="User not found.")

    data = request.get_json() or {}
    allowed_roles = {"user", "moderator", "admin"}
    allowed_status = {"active", "suspended"}
    allowed_tiers = {"free", "pro", "enterprise"}

    if "email" in data:
        user.email = data["email"]
    if "username" in data:
        user.username = data["username"]
    if "role" in data:
        new_role = data["role"]
        if new_role not in allowed_roles:
            abort(400, description="Invalid role provided.")
        user.role = new_role
    if "account_status" in data:
        new_status = data["account_status"]
        if new_status not in allowed_status:
            abort(400, description="Invalid account status provided.")
        user.account_status = new_status
    if "subscription_tier" in data:
        new_tier = data["subscription_tier"]
        if new_tier not in allowed_tiers:
            abort(400, description="Invalid subscription tier provided.")
        user.subscription_tier = new_tier

    db.session.commit()
    return jsonify({"message": "User updated successfully."}), 200

if __name__ == '__main__':
    app.run(debug=True)